import React from "react";

function Hero({ setPage }) {
  return (
    <section className="hero-section">
      <div className="hero-overlay" />
      <div className="hero-content container">
        <p className="hero-kicker">City Public Works Digital Portal</p>
        <h1>National Urban Drainage Monitoring Dashboard</h1>
        <p className="hero-text">
          This official platform provides real-time drainage status, risk monitoring,
          and coordinated response support to help municipal teams maintain safe,
          resilient, and flood-ready urban infrastructure.
        </p>
        <button className="cta-btn" onClick={() => setPage("login")}>
          Access Official Dashboard
        </button>
      </div>
    </section>
  );
}

export default Hero;
